// BEFORE (wrong):
x := 5
x := 10  // redeclared

// AFTER (correct):
x := 5
x = 10  // assignment, not declaration

// In package {packageName}:
// BEFORE (unexported):
func {symbolName}() {}

// AFTER (exported):
func {symbolName}() {}  // Capitalize first letter

// BEFORE (wrong):
import "time"
t1 := time.Time{}
t2 := t1  // may fail if struct has unexported fields

// AFTER (correct):
import "time"
t1 := time.Now()  // use constructor
t2 := t1          // copy is ok for time.Time

// BEFORE (wrong):
x := 5
x := 10  // no new variables

// AFTER (correct):
x := 5
x = 10  // regular assignment

// BEFORE (wrong):
_, err := doWork()
fmt.Println(_)  // cannot use _ as value

// AFTER (correct):
result, err := doWork()
fmt.Println(result)

// BEFORE (wrong):
var x int32 = 5
var y int64 = x  // cannot use x (type int32) as type int64

// AFTER (correct):
var x int32 = 5
var y int64 = int64(x)

// Interface:
type {interfaceName} interface {
    {missingMethod}() error
}

// BEFORE (wrong):
type {actualType} struct{}
// missing {missingMethod} method

// AFTER (correct):
type {actualType} struct{}

func (t *{actualType}) {missingMethod}() error {
    return nil
}

