// BEFORE (wrong):
var x int = nil

// AFTER (correct):
var x *int = nil
// or
var x int = 0  // zero value

// Fix:
// $ go get {packagePath}
// $ go mod tidy

// BEFORE (circular):
// package a
import "mymod/b"  // a imports b

// package b
import "mymod/a"  // b imports a -> cycle!

// AFTER (fixed):
// package types (new shared package)
type Processor interface { Process() }

// package a
import "mymod/types"

// package b
import "mymod/types"

// Fix:
// $ go get {packagePath}
// $ go mod tidy

// Fix:
// $ go mod init github.com/username/projectname
// $ go mod tidy

// Fix:
// $ go get {module}@latest
// $ go mod tidy

// BEFORE (wrong):
fmt.Println(strconv.Atoi("42"))  // Atoi returns (int, error)

// AFTER (correct):
n, err := strconv.Atoi("42")
if err != nil {
    log.Fatal(err)
}
fmt.Println(n)

// BEFORE (wrong):
func f() int {
    return 42
    fmt.Println("never runs")  // unreachable
}

// AFTER (correct):
func f() int {
    fmt.Println("runs first")
    return 42
}

// BEFORE (resource leak):
for _, name := range files {
    f, _ := os.Open(name)
    defer f.Close()  // won't close until function returns
}

// AFTER (correct):
for _, name := range files {
    func() {
        f, _ := os.Open(name)
        defer f.Close()
        // use f
    }()
}

// BEFORE (panic):
ch := make(chan int)
close(ch)
ch <- 42  // panic: send on closed channel

// AFTER (correct):
ch := make(chan int)
go func() {
    ch <- 42
    close(ch)
}()

// BEFORE (race):
var count int
for i := 0; i < 10; i++ {
    go func() { count++ }()
}

// AFTER (correct):
var count int64
for i := 0; i < 10; i++ {
    go func() { atomic.AddInt64(&count, 1) }()
}

// BEFORE (panic):
var ch chan int
close(ch)  // panic

// AFTER (correct):
ch := make(chan int)
close(ch)

// BEFORE (wrong):
type User struct {
    Name string
    Email string
}
u := User{Name: "Alice", Phone: "555"}  // unknown field Phone

// AFTER (correct):
type User struct {
    Name  string
    Email string
    Phone string  // add the field
}
u := User{Name: "Alice", Phone: "555"}

// BEFORE (wrong):
type Point struct { X, Y int }
p := Point{X: 1, 2}  // mixture

// AFTER (correct):
p := Point{X: 1, Y: 2}  // all named
// or
p := Point{1, 2}  // all positional

// BEFORE (wrong):
type Base struct { ID int }
type User struct { Base; Name string }
u := User{ID: 1, Name: "Alice"}  // cannot use promoted field

// AFTER (correct):
u := User{Base: Base{ID: 1}, Name: "Alice"}

// BEFORE (bug in Go <1.22):
for _, v := range items {
    go func() {
        fmt.Println(v)  // always prints last item
    }()
}

// AFTER (correct for all versions):
for _, v := range items {
    v := v  // shadow the variable
    go func() {
        fmt.Println(v)  // correct value
    }()
}

// BEFORE (lost result):
go computeResult()  // return value lost

// AFTER (correct):
ch := make(chan int)
go func() {
    ch <- computeResult()
}()
result := <-ch

// BEFORE (wrong):
fmt.Printf("value is", x)  // missing %v

// AFTER (correct):
fmt.Printf("value is %v", x)
// or
fmt.Println("value is", x)

// BEFORE (wrong):
fmt.Printf("name: %d", "Alice")  // %d is for integers

// AFTER (correct):
fmt.Printf("name: %s", "Alice")

// BEFORE (wrong):
type Counter struct {
    mu sync.Mutex
    n  int
}
func (c Counter) Get() int { ... }  // copies lock

// AFTER (correct):
func (c *Counter) Get() int { ... }  // pointer receiver

// BEFORE (wrong):
type User struct {
    Name string `json:name`  // missing quotes
}

// AFTER (correct):
type User struct {
    Name string `json:"name"`
}

// BEFORE (wrong):
if err != nil  // correct, err is a variable
if myFunc == nil  // always true/false, comparing function itself

// AFTER (correct):
if myFunc() == nil  // call the function first

// BEFORE (shadow bug):
err := doFirst()
if true {
    result, err := doSecond()  // shadows outer err
    _ = result
}
// outer err is still from doFirst!

// AFTER (correct):
err := doFirst()
if true {
    var result int
    result, err = doSecond()  // reuses outer err
    _ = result
}

// BEFORE (wrong):
fmt.Printf(userInput)  // potential format string vulnerability

// AFTER (correct):
fmt.Print(userInput)
// or
fmt.Printf("%s", userInput)

// BEFORE (wrong):
db.QueryContext(nil, query)

// AFTER (correct):
db.QueryContext(context.Background(), query)

// BEFORE (wrong):
ctx = context.WithValue(ctx, "userID", 42)

// AFTER (correct):
type ctxKey struct{}
var userIDKey = ctxKey{}
ctx = context.WithValue(ctx, userIDKey, 42)

// BEFORE (wrong):
append(items, newItem)  // result lost

// AFTER (correct):
items = append(items, newItem)

// BEFORE (wrong):
f, err := os.Open("file")
defer f.Close()
if err != nil { return err }

// AFTER (correct):
f, err := os.Open("file")
if err != nil { return err }
defer f.Close()

// BEFORE:
select {
case v := <-ch:
    fmt.Println(v)
}

// AFTER:
v := <-ch
fmt.Println(v)

// BEFORE:
for i := range src {
    dst[i] = src[i]
}

// AFTER:
copy(dst, src)

// BEFORE:
s := fmt.Sprintf("%s", myError)

// AFTER:
s := myError.Error()

//go:build linux
// +build linux

// This file only compiles on Linux.
// Add a file with //go:build !linux for other platforms.

// Fix:
// $ CGO_ENABLED=1 go build ./...
// or use a pure-Go alternative

// BEFORE (ambiguous):
type A struct{ Name string }
type B struct{ Name string }
type C struct{ A; B }
c := C{}
fmt.Println(c.Name)  // ambiguous

// AFTER (explicit):
fmt.Println(c.A.Name)
fmt.Println(c.B.Name)

// BEFORE (wrong):
var x int = 42
y := x.(string)  // x is not an interface

// AFTER (correct):
var x interface{} = 42
y, ok := x.(int)  // type assertion on interface

// BEFORE (cannot infer):
func Map[T, U any](s []T, f func(T) U) []U { ... }
result := Map(nil, strconv.Itoa)  // cannot infer T from nil

// AFTER (explicit):
result := Map[int, string](nil, strconv.Itoa)

// Methods CANNOT have type parameters:
// WRONG:
func (s *MyStruct) DoWork[T any](val T) {}  // not allowed

// CORRECT — use a generic type instead:
type MyStruct[T any] struct{}
func (s *MyStruct[T]) DoWork(val T) {}

// BEFORE (wrong):
const maxSize = len(os.Args)  // not a constant

// AFTER (correct):
var maxSize = len(os.Args)

// BEFORE (overflow):
const big int8 = 256  // max int8 is 127

// AFTER (correct):
const big int16 = 256

// BEFORE (cycle):
var a = b + 1
var b = a + 1  // cycle

// AFTER (correct):
var a int
var b int
func init() {
    a = 1
    b = a + 1
}

errors.prescription:
1. Capture and check the error: if err := funcCall(); err != nil { return err }
2. If you intentionally want to ignore the error, assign it to _: _ = funcCall()
3. Consider wrapping the error with context: fmt.Errorf("context: %w", err)

errors.codeBlock:
// BEFORE (unchecked):
os.Remove("file.txt")

// AFTER (checked):
if err := os.Remove("file.txt"); err != nil {
    return fmt.Errorf("failed to remove file: %w", err)
}

// BEFORE (wrong):
return fmt.Errorf("Failed to connect.")

// AFTER (correct):
return fmt.Errorf("failed to connect")

// BEFORE (wrong):
return fmt.Errorf("failed: %v", err)  // loses error chain

// AFTER (correct):
return fmt.Errorf("failed: %w", err)  // preserves error chain

