// mymod/cmd/server/main.go — CAN import mymod/internal/auth
// othermod/main.go — CANNOT import mymod/internal/auth

// package a
import "mymod/b"  // ERROR if b also imports a

// Solutions:
// 1. Extract shared types to package c
// 2. Define interface in a, implement in b
// 3. Use dependency injection

